#!/usr/bin/env python3\n\"\"\"\nEnhanced Data Collector for AI Training\nCollects real market data using existing bot infrastructure\n\"\"\"\n\nimport os\nimport sys\nimport pandas as pd\nimport numpy as np\nimport sqlite3\nimport requests\nimport time\nfrom datetime import datetime, timedelta\nimport logging\nfrom pathlib import Path\n\n# Setup logging\nlogging.basicConfig(\n    level=logging.INFO,\n    format='%(asctime)s - DataCollector - %(levelname)s - %(message)s'\n)\nlogger = logging.getLogger(__name__)\n\nclass EnhancedDataCollector:\n    \"\"\"Enhanced data collector using existing bot infrastructure\"\"\"\n    \n    def __init__(self):\n        self.db_path = \"crypto_trading_data.db\"\n        self.symbols = ['BTCUSDT', 'ETHUSDT', 'ADAUSDT', 'BNBUSDT', 'XRPUSDT']\n        self.timeframes = ['1h', '4h', '1d']\n        \n        # Create training data directory\n        Path(\"training_data\").mkdir(exist_ok=True)\n        \n        logger.info(\"Enhanced Data Collector initialized\")\n    \n    def collect_binance_data(self, symbol: str, interval: str = '1h', limit: int = 500) -> pd.DataFrame:\n        \"\"\"Collect data from Binance public API\"\"\"\n        try:\n            url = \"https://api.binance.com/api/v3/klines\"\n            params = {\n                'symbol': symbol,\n                'interval': interval,\n                'limit': limit\n            }\n            \n            logger.info(f\"📊 Fetching {symbol} {interval} data ({limit} candles)...\")\n            \n            response = requests.get(url, params=params, timeout=30)\n            response.raise_for_status()\n            data = response.json()\n            \n            if not data:\n                logger.warning(f\"No data received for {symbol}\")\n                return pd.DataFrame()\n            \n            # Convert to DataFrame\n            df = pd.DataFrame(data, columns=[\n                'timestamp', 'open', 'high', 'low', 'close', 'volume',\n                'close_time', 'quote_volume', 'trades', 'taker_buy_base',\n                'taker_buy_quote', 'ignore'\n            ])\n            \n            # Convert data types\n            df['timestamp'] = pd.to_datetime(df['timestamp'], unit='ms')\n            for col in ['open', 'high', 'low', 'close', 'volume']:\n                df[col] = df[col].astype(float)\n            \n            # Add symbol info\n            df['symbol'] = symbol\n            df['timeframe'] = interval\n            \n            # Keep only needed columns\n            df = df[['timestamp', 'symbol', 'timeframe', 'open', 'high', 'low', 'close', 'volume']]\n            \n            logger.info(f\"✅ Collected {len(df)} records for {symbol} {interval}\")\n            return df\n            \n        except Exception as e:\n            logger.error(f\"❌ Failed to collect {symbol} {interval}: {e}\")\n            return pd.DataFrame()\n    \n    def store_to_database(self, df: pd.DataFrame, table_name: str = 'market_data'):\n        \"\"\"Store data to existing database\"\"\"\n        if df.empty:\n            return\n        \n        try:\n            conn = sqlite3.connect(self.db_path)\n            \n            # Create table if it doesn't exist\n            cursor = conn.cursor()\n            cursor.execute(f\"\"\"\n                CREATE TABLE IF NOT EXISTS {table_name} (\n                    id INTEGER PRIMARY KEY AUTOINCREMENT,\n                    timestamp TEXT NOT NULL,\n                    symbol TEXT NOT NULL,\n                    timeframe TEXT NOT NULL,\n                    open REAL NOT NULL,\n                    high REAL NOT NULL,\n                    low REAL NOT NULL,\n                    close REAL NOT NULL,\n                    volume REAL NOT NULL,\n                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n                    UNIQUE(timestamp, symbol, timeframe)\n                )\n            \"\"\")\n            \n            # Insert data\n            for _, row in df.iterrows():\n                cursor.execute(f\"\"\"\n                    INSERT OR REPLACE INTO {table_name} \n                    (timestamp, symbol, timeframe, open, high, low, close, volume)\n                    VALUES (?, ?, ?, ?, ?, ?, ?, ?)\n                \"\"\", (\n                    row['timestamp'].isoformat(),\n                    row['symbol'],\n                    row['timeframe'],\n                    float(row['open']),\n                    float(row['high']),\n                    float(row['low']),\n                    float(row['close']),\n                    float(row['volume'])\n                ))\n            \n            conn.commit()\n            conn.close()\n            \n            logger.info(f\"✅ Stored {len(df)} records to {table_name}\")\n            \n        except Exception as e:\n            logger.error(f\"❌ Failed to store data: {e}\")\n    \n    def collect_comprehensive_dataset(self):\n        \"\"\"Collect comprehensive dataset for AI training\"\"\"\n        \n        logger.info(\"🚀 Starting comprehensive data collection\")\n        logger.info(f\"📊 Symbols: {len(self.symbols)}\")\n        logger.info(f\"⏰ Timeframes: {len(self.timeframes)}\")\n        \n        total_collections = len(self.symbols) * len(self.timeframes)\n        completed = 0\n        all_data = []\n        \n        for symbol in self.symbols:\n            for timeframe in self.timeframes:\n                try:\n                    logger.info(f\"📈 [{completed+1}/{total_collections}] Collecting {symbol} {timeframe}...\")\n                    \n                    # Collect data\n                    df = self.collect_binance_data(symbol, timeframe, 500)\n                    \n                    if not df.empty:\n                        # Store to database\n                        self.store_to_database(df)\n                        all_data.append(df)\n                        \n                        # Save individual CSV\n                        csv_path = f\"training_data/{symbol}_{timeframe}_data.csv\"\n                        df.to_csv(csv_path, index=False)\n                    \n                    completed += 1\n                    \n                    # Rate limiting - be respectful\n                    time.sleep(1)\n                    \n                except Exception as e:\n                    logger.error(f\"❌ Failed to collect {symbol} {timeframe}: {e}\")\n                    completed += 1\n                    continue\n        \n        # Combine all data\n        if all_data:\n            combined_df = pd.concat(all_data, ignore_index=True)\n            combined_df.to_csv('training_data/combined_market_data.csv', index=False)\n            logger.info(f\"💾 Combined dataset saved: {len(combined_df)} total records\")\n        \n        logger.info(f\"🎉 Data collection complete! {completed}/{total_collections} collections\")\n        self._generate_summary()\n    \n    def _generate_summary(self):\n        \"\"\"Generate collection summary\"\"\"\n        try:\n            conn = sqlite3.connect(self.db_path)\n            \n            # Get market_data stats\n            cursor = conn.cursor()\n            cursor.execute(\"SELECT COUNT(*) FROM market_data\")\n            total_records = cursor.fetchone()[0]\n            \n            cursor.execute(\"\"\"\n                SELECT symbol, timeframe, COUNT(*) as count,\n                       MIN(timestamp) as earliest,\n                       MAX(timestamp) as latest\n                FROM market_data \n                GROUP BY symbol, timeframe\n                ORDER BY symbol, timeframe\n            \"\"\")\n            \n            stats = cursor.fetchall()\n            conn.close()\n            \n            logger.info(f\"📊 COLLECTION SUMMARY\")\n            logger.info(f\"=\" * 50)\n            logger.info(f\"Total Records: {total_records:,}\")\n            logger.info(f\"Symbols: {len(set(s[0] for s in stats))}\")\n            logger.info(f\"Timeframes: {len(set(s[1] for s in stats))}\")\n            \n            logger.info(f\"\\n📈 Data Coverage:\")\n            for symbol, timeframe, count, earliest, latest in stats:\n                logger.info(f\"   {symbol} {timeframe}: {count:,} records ({earliest[:10]} to {latest[:10]})\")\n            \n        except Exception as e:\n            logger.error(f\"❌ Failed to generate summary: {e}\")\n    \n    def get_training_data(self, timeframe: str = '1h', limit: int = 5000) -> pd.DataFrame:\n        \"\"\"Get training data for AI models\"\"\"\n        try:\n            conn = sqlite3.connect(self.db_path)\n            \n            query = \"\"\"\n                SELECT timestamp, symbol, open, high, low, close, volume\n                FROM market_data \n                WHERE timeframe = ?\n                ORDER BY timestamp DESC\n                LIMIT ?\n            \"\"\"\n            \n            df = pd.read_sql_query(query, conn, params=(timeframe, limit))\n            conn.close()\n            \n            if not df.empty:\n                df['timestamp'] = pd.to_datetime(df['timestamp'])\n                df = df.sort_values('timestamp').reset_index(drop=True)\n                \n                # Add basic technical indicators\n                for symbol in df['symbol'].unique():\n                    symbol_mask = df['symbol'] == symbol\n                    symbol_data = df[symbol_mask].copy()\n                    \n                    # Price changes\n                    symbol_data['price_change'] = symbol_data['close'].pct_change()\n                    symbol_data['price_change_5'] = symbol_data['close'].pct_change(5)\n                    \n                    # Simple moving averages\n                    symbol_data['sma_20'] = symbol_data['close'].rolling(20).mean()\n                    symbol_data['sma_50'] = symbol_data['close'].rolling(50).mean()\n                    \n                    # Volatility\n                    symbol_data['volatility'] = symbol_data['close'].rolling(20).std()\n                    \n                    # Update main dataframe\n                    df.loc[symbol_mask, ['price_change', 'price_change_5', 'sma_20', 'sma_50', 'volatility']] = symbol_data[['price_change', 'price_change_5', 'sma_20', 'sma_50', 'volatility']]\n                \n                logger.info(f\"✅ Retrieved {len(df)} training records with indicators\")\n            \n            return df\n            \n        except Exception as e:\n            logger.error(f\"❌ Failed to get training data: {e}\")\n            return pd.DataFrame()\n    \n    def export_for_ai_training(self) -> str:\n        \"\"\"Export data optimized for AI training\"\"\"\n        try:\n            logger.info(\"📤 Exporting data for AI training...\")\n            \n            # Get 1h data (best for training)\n            df = self.get_training_data('1h', 10000)\n            \n            if df.empty:\n                logger.warning(\"No data available for export\")\n                return \"\"\n            \n            # Remove NaN values\n            df = df.dropna()\n            \n            # Save to CSV\n            output_path = 'training_data/ai_training_dataset.csv'\n            df.to_csv(output_path, index=False)\n            \n            logger.info(f\"✅ Exported {len(df)} records to {output_path}\")\n            logger.info(f\"📊 Data shape: {df.shape}\")\n            logger.info(f\"📅 Date range: {df['timestamp'].min()} to {df['timestamp'].max()}\")\n            logger.info(f\"💱 Symbols: {df['symbol'].unique()}\")\n            \n            return output_path\n            \n        except Exception as e:\n            logger.error(f\"❌ Failed to export training data: {e}\")\n            return \"\"\n\ndef main():\n    \"\"\"Main function\"\"\"\n    print(\"🚀 Enhanced Data Collector for AI Training\")\n    print(\"=\" * 60)\n    \n    collector = EnhancedDataCollector()\n    \n    # Collect comprehensive dataset\n    print(\"\\n📊 Starting data collection...\")\n    print(\"This will collect real market data from Binance API\")\n    print(f\"   • {len(collector.symbols)} symbols\")\n    print(f\"   • {len(collector.timeframes)} timeframes\")\n    print(f\"   • 500 candles per request\")\n    print(\"\\n⏰ This will take 2-3 minutes...\")\n    \n    collector.collect_comprehensive_dataset()\n    \n    # Export for AI training\n    print(\"\\n📤 Exporting optimized training dataset...\")\n    export_path = collector.export_for_ai_training()\n    \n    if export_path:\n        print(f\"\\n🎉 SUCCESS! Training data ready at: {export_path}\")\n        print(\"\\n🔥 Next steps:\")\n        print(\"   1. Your real market data is now ready!\")\n        print(\"   2. Advanced AI models can train on this data\")\n        print(\"   3. Run training to see improved performance!\")\n        \n        # Show sample\n        df = pd.read_csv(export_path)\n        print(f\"\\n📊 Dataset summary:\")\n        print(f\"   Records: {len(df):,}\")\n        print(f\"   Columns: {len(df.columns)}\")\n        print(f\"   Symbols: {df['symbol'].nunique()}\")\n        print(f\"   Date range: {df['timestamp'].min()} to {df['timestamp'].max()}\")\n    else:\n        print(\"\\n❌ Failed to export training data\")\n    \n    print(\"\\n\" + \"=\"*60)\n    print(\"Enhanced Data Collection Complete! 🎉\")\n\nif __name__ == \"__main__\":\n    main()" 